class Solution {
    public int numberOfWays(int n, int x) {
        int mod = 1000000007;
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= i; j++) {
                if (j * (int) Math.pow(x, x - 1) <= i) {
                    dp[i] = (dp[i] + dp[i - (int) (j * Math.pow(x, x - 1))]) % mod;
                }
            }
        }
        return dp[n];
    }
}
